{
  "name": "Sistem Penjana Minit Curai PK19/6",
  "description": "A web application for generating Malaysian school 'Minit Curai' reports in PK19/6 format, featuring a warm and bright UI with PDF export capabilities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MinitIssue {
  id: string;
  perkara: string;
  tindakan: string;
}

export interface MinitData {
  perkara: string;
  tarikh: string;
  rujukanFail: string;
  masa: string;
  tempat: string;
  anjuran: string;
  kehadiran: string;
  pencatat: string;
  tarikhDisediakan: string;
  issues: MinitIssue[];
}

import React, { useState } from 'react';
import { Plus, Trash2, FileText, Download, User, Calendar, Clock, MapPin, Building, Hash, ClipboardList } from 'lucide-react';
import { MinitData, MinitIssue } from './types';
import { generatePDF } from './services/pdfService';

const App: React.FC = () => {
  const [data, setData] = useState<MinitData>({
    perkara: '',
    tarikh: new Date().toISOString().split('T')[0],
    rujukanFail: '-',
    masa: '',
    tempat: '',
    anjuran: '',
    kehadiran: '',
    pencatat: '',
    tarikhDisediakan: new Date().toISOString().split('T')[0],
    issues: [{ id: crypto.randomUUID(), perkara: '', tindakan: '' }]
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };

  const addIssue = () => {
    setData(prev => ({
      ...prev,
      issues: [...prev.issues, { id: crypto.randomUUID(), perkara: '', tindakan: '' }]
    }));
  };

  const removeIssue = (id: string) => {
    if (data.issues.length <= 1) return;
    setData(prev => ({
      ...prev,
      issues: prev.issues.filter(issue => issue.id !== id)
    }));
  };

  const updateIssue = (id: string, field: keyof MinitIssue, value: string) => {
    setData(prev => ({
      ...prev,
      issues: prev.issues.map(issue => issue.id === id ? { ...issue, [field]: value } : issue)
    }));
  };

  const handleDownload = () => {
    generatePDF(data);
  };

  return (
    <div className="max-w-4xl mx-auto py-10 px-4">
      <header className="mb-10 text-center">
        <div className="inline-flex p-3 bg-amber-100 rounded-full mb-4">
          <FileText className="w-8 h-8 text-amber-600" />
        </div>
        <h1 className="text-3xl font-bold text-amber-900">Sistem Penjana Minit Curai</h1>
        <p className="text-amber-700 mt-2">Borang PK19/6 - Pengurusan Sukan Dan Permainan</p>
      </header>

      <main className="bg-white rounded-2xl shadow-xl shadow-amber-100/50 overflow-hidden border border-amber-100">
        {/* Basic Info Section */}
        <div className="p-8 bg-gradient-to-br from-amber-50 to-white border-b border-amber-100">
          <h2 className="text-lg font-semibold text-amber-800 mb-6 flex items-center gap-2">
            <ClipboardList className="w-5 h-5" />
            Maklumat Utama
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <FormField label="Perkara" icon={<FileText size={18} />}>
              <input
                type="text"
                name="perkara"
                value={data.perkara}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Tajuk mesyuarat/kursus/taklimat"
              />
            </FormField>

            <FormField label="Tarikh" icon={<Calendar size={18} />}>
              <input
                type="date"
                name="tarikh"
                value={data.tarikh}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
              />
            </FormField>

            <FormField label="Rujukan Fail" icon={<Hash size={18} />}>
              <input
                type="text"
                name="rujukanFail"
                value={data.rujukanFail}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Rujukan fail surat panggilan"
              />
            </FormField>

            <FormField label="Masa" icon={<Clock size={18} />}>
              <input
                type="text"
                name="masa"
                value={data.masa}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Contoh: 8:00 Pagi - 1:00 Tengahari"
              />
            </FormField>

            <FormField label="Tempat" icon={<MapPin size={18} />}>
              <input
                type="text"
                name="tempat"
                value={data.tempat}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Lokasi acara"
              />
            </FormField>

            <FormField label="Anjuran" icon={<Building size={18} />}>
              <input
                type="text"
                name="anjuran"
                value={data.anjuran}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Nama penganjur"
              />
            </FormField>

            <div className="md:col-span-2">
              <FormField label="Kehadiran" icon={<User size={18} />}>
                <textarea
                  name="kehadiran"
                  value={data.kehadiran}
                  onChange={handleInputChange}
                  rows={2}
                  className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                  placeholder="Senarai nama guru/staff yang hadir"
                />
              </FormField>
            </div>
          </div>
        </div>

        {/* Issues/Actions Section */}
        <div className="p-8">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-semibold text-amber-800 flex items-center gap-2">
              <ClipboardList className="w-5 h-5" />
              Perkara / Isu dan Tindakan
            </h2>
            <button
              onClick={addIssue}
              className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white rounded-lg font-medium transition-colors shadow-lg shadow-amber-200"
            >
              <Plus size={18} />
              Tambah Isu
            </button>
          </div>

          <div className="space-y-4">
            {data.issues.map((issue, index) => (
              <div
                key={issue.id}
                className="group relative flex flex-col md:flex-row gap-4 p-4 rounded-xl border border-amber-100 bg-amber-50/30 hover:bg-amber-50 transition-colors"
              >
                <div className="flex-none w-10 h-10 bg-amber-100 text-amber-700 rounded-full flex items-center justify-center font-bold">
                  {index + 1}
                </div>
                <div className="flex-grow space-y-3">
                  <div className="flex flex-col gap-1">
                    <label className="text-xs font-semibold text-amber-600 uppercase tracking-wider">Perkara / Isu</label>
                    <textarea
                      value={issue.perkara}
                      onChange={(e) => updateIssue(issue.id, 'perkara', e.target.value)}
                      placeholder="Tuliskan perkara atau isu utama di sini..."
                      className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none min-h-[80px]"
                    />
                  </div>
                  <div className="flex flex-col gap-1">
                    <label className="text-xs font-semibold text-amber-600 uppercase tracking-wider">Tindakan / Makluman</label>
                    <textarea
                      value={issue.tindakan}
                      onChange={(e) => updateIssue(issue.id, 'tindakan', e.target.value)}
                      placeholder="Tuliskan tindakan atau makluman sewajarnya..."
                      className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none min-h-[60px]"
                    />
                  </div>
                </div>
                <button
                  onClick={() => removeIssue(issue.id)}
                  disabled={data.issues.length <= 1}
                  className="absolute -top-2 -right-2 md:static flex-none p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-all opacity-0 group-hover:opacity-100 disabled:hidden"
                  title="Padam Isu"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Footer info (Pencatat) */}
        <div className="p-8 border-t border-amber-100 bg-amber-50/20">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <FormField label="Nama Pencatat" icon={<User size={18} />}>
              <input
                type="text"
                name="pencatat"
                value={data.pencatat}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Nama penyedia laporan"
              />
            </FormField>

            <FormField label="Tarikh Disediakan" icon={<Calendar size={18} />}>
              <input
                type="date"
                name="tarikhDisediakan"
                value={data.tarikhDisediakan}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
              />
            </FormField>
          </div>

          <div className="mt-10 flex justify-center">
            <button
              onClick={handleDownload}
              className="flex items-center gap-3 px-10 py-4 bg-amber-600 hover:bg-amber-700 text-white rounded-xl font-bold text-lg transition-all shadow-xl shadow-amber-200 transform hover:-translate-y-1"
            >
              <Download size={24} />
              Jana PDF Minit Curai
            </button>
          </div>
        </div>
      </main>

      <footer className="mt-10 text-center text-amber-700/60 text-sm">
        <p>Hak Cipta Terpelihara &copy; {new Date().getFullYear()} - Format PK19/6</p>
      </footer>
    </div>
  );
};

const FormField: React.FC<{ label: string; icon: React.ReactNode; children: React.ReactNode }> = ({ label, icon, children }) => {
  return (
    <div className="flex flex-col gap-2">
      <label className="text-sm font-semibold text-amber-700 flex items-center gap-2">
        {icon}
        {label}
      </label>
      {children}
    </div>
  );
};

export default App;

import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { MinitData } from '../types';

export const generatePDF = (data: MinitData) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  // Basic settings
  const margin = 15;
  const pageWidth = doc.internal.pageSize.getWidth();
  const contentWidth = pageWidth - (margin * 2);

  // Header text small
  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(8);
  doc.text('PK19 – Pengurusan Sukan Dan Permainan', pageWidth - margin, 10, { align: 'right' });
  doc.line(margin, 12, pageWidth - margin, 12);

  // PK19/6 tag
  doc.setFont('Helvetica', 'bold');
  doc.setFontSize(11);
  doc.text('PK19/6', pageWidth - margin, 18, { align: 'right' });

  // Title
  doc.setFontSize(12);
  doc.text('MINIT CURAI', pageWidth / 2, 25, { align: 'center' });

  // Info Grid (2 columns, 3 rows)
  const gridStartY = 30;
  const rowHeight = 7;
  const colWidth = contentWidth / 2;

  doc.setFontSize(10);
  doc.setFont('Helvetica', 'normal');

  // Drawing the grid for top details
  const drawRow = (y: number, label1: string, value1: string, label2: string, value2: string) => {
    // Left col
    doc.rect(margin, y, colWidth, rowHeight);
    doc.setFont('Helvetica', 'bold');
    doc.text(label1, margin + 2, y + 5);
    doc.setFont('Helvetica', 'normal');
    doc.text(value1 || '', margin + 25, y + 5);

    // Right col
    doc.rect(margin + colWidth, y, colWidth, rowHeight);
    doc.setFont('Helvetica', 'bold');
    doc.text(label2, margin + colWidth + 2, y + 5);
    doc.setFont('Helvetica', 'normal');
    doc.text(value2 || '', margin + colWidth + 25, y + 5);
  };

  drawRow(gridStartY, 'PERKARA', data.perkara, 'TARIKH', formatDate(data.tarikh));
  drawRow(gridStartY + rowHeight, 'RUJ. FAIL', data.rujukanFail, 'MASA', data.masa);
  drawRow(gridStartY + (rowHeight * 2), 'TEMPAT', data.tempat, 'ANJURAN', data.anjuran);

  // Kehadiran section
  const attendanceY = gridStartY + (rowHeight * 3);
  doc.rect(margin, attendanceY, contentWidth, rowHeight * 2);
  doc.setFont('Helvetica', 'bold');
  doc.text('KEHADIRAN :', margin + 2, attendanceY + 5);
  doc.setFont('Helvetica', 'normal');
  const attendanceLines = doc.splitTextToSize(data.kehadiran || '', contentWidth - 35);
  doc.text(attendanceLines, margin + 30, attendanceY + 5);

  // Issues Table
  const tableStartY = attendanceY + (rowHeight * 2);

  autoTable(doc, {
    startY: tableStartY,
    margin: { left: margin, right: margin },
    head: [['BIL', 'PERKARA / ISU', 'TINDAKAN / MAKLUMAN']],
    body: data.issues.map((issue, index) => [
      (index + 1).toString(),
      issue.perkara,
      issue.tindakan
    ]),
    theme: 'plain',
    styles: {
      font: 'Helvetica',
      fontSize: 10,
      cellPadding: 3,
      lineColor: [0, 0, 0],
      lineWidth: 0.1,
      textColor: [0, 0, 0],
      valign: 'top',
    },
    headStyles: {
      fillColor: false,
      fontStyle: 'bold',
      halign: 'center',
    },
    columnStyles: {
      0: { cellWidth: 12, halign: 'center' },
      1: { cellWidth: (contentWidth - 12) * 0.7 },
      2: { cellWidth: (contentWidth - 12) * 0.3 },
    },
  });

  // Footer Section (Nama Pencatat & Tarikh)
  const finalY = (doc as any).lastAutoTable.finalY + 0;

  // Only draw boxes if there's enough space on page, else it auto-wraps but we'll stick to a simple block
  const footerHeight = 15;
  doc.rect(margin, finalY, colWidth, footerHeight);
  doc.setFont('Helvetica', 'normal');
  doc.text('Nama Pencatat :', margin + 2, finalY + 5);
  doc.setFont('Helvetica', 'bold');
  doc.text(data.pencatat || '', margin + 2, finalY + 11);

  doc.rect(margin + colWidth, finalY, colWidth, footerHeight);
  doc.setFont('Helvetica', 'normal');
  doc.text('Tarikh Disediakan :', margin + colWidth + 2, finalY + 5);
  doc.setFont('Helvetica', 'bold');
  doc.text(formatDate(data.tarikhDisediakan) || '', margin + colWidth + 2, finalY + 11);

  // Bottom Copyright Footer
  const pageHeight = doc.internal.pageSize.getHeight();
  doc.setFontSize(7);
  doc.setFont('Helvetica', 'normal');
  doc.line(margin, pageHeight - 20, pageWidth - margin, pageHeight - 20);
  doc.text('Hak Cipta Terpelihara © Sektor Jaminan Kualiti, Jabatan Pendidikan Negeri Johor', margin, pageHeight - 15);
  doc.text('01 Januari 2018 - Keluaran 01 | Pindaan 00', margin, pageHeight - 11);

  doc.save(`Minit_Curai_${data.perkara.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
};

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  return d.toLocaleDateString('ms-MY', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric'
  });
};

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, FileText, Download, User, Calendar, Clock, MapPin, Building, Hash, ClipboardList } from 'lucide-react';
import { MinitData, MinitIssue } from './types';
import { generatePDF } from './services/pdfService';

const App: React.FC = () => {
  const getInitialDates = () => {
    const today = new Date();
    const tomorrow = new Date();
    tomorrow.setDate(today.getDate() + 1);
    return {
      today: today.toISOString().split('T')[0],
      tomorrow: tomorrow.toISOString().split('T')[0]
    };
  };

  const { today, tomorrow } = getInitialDates();

  const [data, setData] = useState<MinitData>({
    perkara: '',
    tarikh: today,
    rujukanFail: '-',
    masa: '',
    tempat: '',
    anjuran: '',
    kehadiran: '',
    pencatat: '',
    tarikhDisediakan: tomorrow,
    issues: [{ id: crypto.randomUUID(), perkara: '', tindakan: '' }]
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;

    if (name === 'tarikh') {
      const selectedDate = new Date(value);
      if (!isNaN(selectedDate.getTime())) {
        const nextDay = new Date(selectedDate);
        nextDay.setDate(nextDay.getDate() + 1);
        const nextDayStr = nextDay.toISOString().split('T')[0];
        setData(prev => ({ 
          ...prev, 
          tarikh: value,
          tarikhDisediakan: nextDayStr 
        }));
      } else {
        setData(prev => ({ ...prev, [name]: value }));
      }
    } else {
      setData(prev => ({ ...prev, [name]: value }));
    }
  };

  const addIssue = () => {
    setData(prev => ({
      ...prev,
      issues: [...prev.issues, { id: crypto.randomUUID(), perkara: '', tindakan: '' }]
    }));
  };

  const removeIssue = (id: string) => {
    if (data.issues.length <= 1) return;
    setData(prev => ({
      ...prev,
      issues: prev.issues.filter(issue => issue.id !== id)
    }));
  };

  const updateIssue = (id: string, field: keyof MinitIssue, value: string) => {
    setData(prev => ({
      ...prev,
      issues: prev.issues.map(issue => issue.id === id ? { ...issue, [field]: value } : issue)
    }));
  };

  const handleDownload = () => {
    generatePDF(data);
  };

  return (
    <div className="max-w-4xl mx-auto py-10 px-4">
      <header className="mb-10 text-center">
        <div className="inline-flex p-3 bg-amber-100 rounded-full mb-4">
          <FileText className="w-8 h-8 text-amber-600" />
        </div>
        <h1 className="text-3xl font-bold text-amber-900">Sistem Penjana Minit Curai</h1>
        <p className="text-amber-700 mt-2">Borang PK19/6 - Pengurusan Sukan Dan Permainan</p>
      </header>

      <main className="bg-white rounded-2xl shadow-xl shadow-amber-100/50 overflow-hidden border border-amber-100">
        {/* Basic Info Section */}
        <div className="p-8 bg-gradient-to-br from-amber-50 to-white border-b border-amber-100">
          <h2 className="text-lg font-semibold text-amber-800 mb-6 flex items-center gap-2">
            <ClipboardList className="w-5 h-5" />
            Maklumat Utama
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <FormField label="Nama" icon={<User size={18} />}>
                <input
                  type="text"
                  name="pencatat"
                  value={data.pencatat}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                  placeholder="Masukkan nama anda"
                />
              </FormField>
            </div>

            <FormField label="Perkara" icon={<FileText size={18} />}>
              <input
                type="text"
                name="perkara"
                value={data.perkara}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Tajuk mesyuarat/kursus/taklimat"
              />
            </FormField>

            <FormField label="Tarikh Bengkel / Acara" icon={<Calendar size={18} />}>
              <input
                type="date"
                name="tarikh"
                value={data.tarikh}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
              />
            </FormField>

            <FormField label="Rujukan Fail" icon={<Hash size={18} />}>
              <input
                type="text"
                name="rujukanFail"
                value={data.rujukanFail}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Rujukan fail surat panggilan"
              />
            </FormField>

            <FormField label="Masa" icon={<Clock size={18} />}>
              <input
                type="text"
                name="masa"
                value={data.masa}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Contoh: 8:00 Pagi - 1:00 Tengahari"
              />
            </FormField>

            <FormField label="Tempat" icon={<MapPin size={18} />}>
              <input
                type="text"
                name="tempat"
                value={data.tempat}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Lokasi acara"
              />
            </FormField>

            <FormField label="Anjuran" icon={<Building size={18} />}>
              <input
                type="text"
                name="anjuran"
                value={data.anjuran}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                placeholder="Nama penganjur"
              />
            </FormField>

            <div className="md:col-span-2">
              <FormField label="Kehadiran" icon={<User size={18} />}>
                <textarea
                  name="kehadiran"
                  value={data.kehadiran}
                  onChange={handleInputChange}
                  rows={2}
                  className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
                  placeholder="Senarai nama guru/staff yang hadir"
                />
              </FormField>
            </div>
          </div>
        </div>

        {/* Issues/Actions Section */}
        <div className="p-8">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-semibold text-amber-800 flex items-center gap-2">
              <ClipboardList className="w-5 h-5" />
              Perkara / Isu dan Tindakan
            </h2>
            <button
              onClick={addIssue}
              className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white rounded-lg font-medium transition-colors shadow-lg shadow-amber-200"
            >
              <Plus size={18} />
              Tambah Isu
            </button>
          </div>

          <div className="space-y-4">
            {data.issues.map((issue, index) => (
              <div
                key={issue.id}
                className="group relative flex flex-col md:flex-row gap-4 p-4 rounded-xl border border-amber-100 bg-amber-50/30 hover:bg-amber-50 transition-colors"
              >
                <div className="flex-none w-10 h-10 bg-amber-100 text-amber-700 rounded-full flex items-center justify-center font-bold">
