import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { MinitData } from '../types';

export const generatePDF = (data: MinitData) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  // Basic settings
  const margin = 15;
  const pageWidth = doc.internal.pageSize.getWidth();
  const contentWidth = pageWidth - (margin * 2);

  // Header text small
  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(8);
  doc.text('PK19 – Pengurusan Sukan Dan Permainan', pageWidth - margin, 10, { align: 'right' });
  doc.line(margin, 12, pageWidth - margin, 12);

  // PK19/6 tag
  doc.setFont('Helvetica', 'bold');
  doc.setFontSize(11);
  doc.text('PK19/6', pageWidth - margin, 18, { align: 'right' });

  // Title
  doc.setFontSize(12);
  doc.text('MINIT CURAI', pageWidth / 2, 25, { align: 'center' });

  // Info Grid (2 columns, 3 rows)
  const gridStartY = 30;
  const rowHeight = 7;
  const colWidth = contentWidth / 2;

  doc.setFontSize(10);
  doc.setFont('Helvetica', 'normal');

  // Drawing the grid for top details
  const drawRow = (y: number, label1: string, value1: string, label2: string, value2: string) => {
    // Left col
    doc.rect(margin, y, colWidth, rowHeight);
    doc.setFont('Helvetica', 'bold');
    doc.text(label1, margin + 2, y + 5);
    doc.setFont('Helvetica', 'normal');
    doc.text(value1 || '', margin + 25, y + 5);

    // Right col
    doc.rect(margin + colWidth, y, colWidth, rowHeight);
    doc.setFont('Helvetica', 'bold');
    doc.text(label2, margin + colWidth + 2, y + 5);
    doc.setFont('Helvetica', 'normal');
    doc.text(value2 || '', margin + colWidth + 25, y + 5);
  };

  const masaDisplay = `${data.masaMula} - ${data.masaTamat}`;

  drawRow(gridStartY, 'PERKARA', data.perkara, 'TARIKH', formatDate(data.tarikh));
  drawRow(gridStartY + rowHeight, 'RUJ. FAIL', data.rujukanFail, 'MASA', masaDisplay);
  drawRow(gridStartY + (rowHeight * 2), 'TEMPAT', data.tempat, 'ANJURAN', data.anjuran);

  // Kehadiran section
  const attendanceY = gridStartY + (rowHeight * 3);
  doc.rect(margin, attendanceY, contentWidth, rowHeight * 2);
  doc.setFont('Helvetica', 'bold');
  doc.text('KEHADIRAN :', margin + 2, attendanceY + 5);
  doc.setFont('Helvetica', 'normal');
  const attendanceLines = doc.splitTextToSize(data.kehadiran || '', contentWidth - 35);
  doc.text(attendanceLines, margin + 30, attendanceY + 5);

  // Issues Table
  const tableStartY = attendanceY + (rowHeight * 2);

  autoTable(doc, {
    startY: tableStartY,
    margin: { left: margin, right: margin },
    head: [['BIL', 'PERKARA / ISU', 'TINDAKAN / MAKLUMAN']],
    body: data.issues.map((issue, index) => [
      (index + 1).toString(),
      issue.perkara,
      issue.tindakan
    ]),
    theme: 'plain',
    styles: {
      font: 'Helvetica',
      fontSize: 10,
      cellPadding: 3,
      lineColor: [0, 0, 0],
      lineWidth: 0.1,
      textColor: [0, 0, 0],
      valign: 'top',
    },
    headStyles: {
      fillColor: false,
      fontStyle: 'bold',
      halign: 'center',
    },
    columnStyles: {
      0: { cellWidth: 12, halign: 'center' },
      1: { cellWidth: (contentWidth - 12) * 0.7 },
      2: { cellWidth: (contentWidth - 12) * 0.3 },
    },
  });

  // Footer Section (Nama Pencatat & Tarikh)
  const finalY = (doc as any).lastAutoTable.finalY + 0;

  // Only draw boxes if there's enough space on page, else it auto-wraps but we'll stick to a simple block
  const footerHeight = 15;
  doc.rect(margin, finalY, colWidth, footerHeight);
  doc.setFont('Helvetica', 'normal');
  doc.text('Nama Pencatat :', margin + 2, finalY + 5);
  doc.setFont('Helvetica', 'bold');
  doc.text(data.pencatat || '', margin + 2, finalY + 11);

  doc.rect(margin + colWidth, finalY, colWidth, footerHeight);
  doc.setFont('Helvetica', 'normal');
  doc.text('Tarikh Disediakan :', margin + colWidth + 2, finalY + 5);
  doc.setFont('Helvetica', 'bold');
  doc.text(formatDate(data.tarikhDisediakan) || '', margin + colWidth + 2, finalY + 11);

  // Bottom Copyright Footer
  const pageHeight = doc.internal.pageSize.getHeight();
  doc.setFontSize(7);
  doc.setFont('Helvetica', 'normal');
  doc.line(margin, pageHeight - 20, pageWidth - margin, pageHeight - 20);
  doc.text('Hak Cipta Terpelihara © Sektor Jaminan Kualiti, Jabatan Pendidikan Negeri Johor', margin, pageHeight - 15);
  doc.text('01 Januari 2018 - Keluaran 01 | Pindaan 00', margin, pageHeight - 11);

  doc.save(`Minit_Curai_${data.perkara.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
};

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  return d.toLocaleDateString('ms-MY', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric'
  });
};

