                    />
                  </div>
                </div>
                <button
                  onClick={() => removeIssue(issue.id)}
                  disabled={data.issues.length <= 1}
                  className="absolute -top-2 -right-2 md:static flex-none p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-all opacity-0 group-hover:opacity-100 disabled:hidden"
                  title="Padam Isu"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
          </div>
        </div>

        <div className="p-8 border-t border-amber-100 bg-amber-50/20">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <FormField label="Nama Pencatat" icon={<User size={18} />}>
              <input
                type="text"
                name="pencatat"
                value={data.pencatat}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none bg-amber-50/50 cursor-not-allowed"
                placeholder="Nama penyedia laporan"
                readOnly
              />
            </FormField>

            <FormField label="Tarikh Disediakan" icon={<Calendar size={18} />}>
              <input
                type="date"
                name="tarikhDisediakan"
                value={data.tarikhDisediakan}
                onChange={handleInputChange}
                className="w-full px-4 py-2 rounded-lg border border-amber-200 focus:ring-2 focus:ring-amber-400 outline-none transition-all"
              />
            </FormField>
          </div>

          <div className="mt-10 flex flex-col sm:flex-row justify-center gap-4">
            <button
              onClick={handlePreview}
              className="flex items-center justify-center gap-3 px-8 py-4 bg-amber-100 hover:bg-amber-200 text-amber-800 rounded-xl font-bold text-lg transition-all border border-amber-200"
            >
              <Eye size={24} />
              Preview PDF
            </button>
            <button
              onClick={handleDownload}
              className="flex items-center justify-center gap-3 px-8 py-4 bg-amber-600 hover:bg-amber-700 text-white rounded-xl font-bold text-lg transition-all shadow-xl shadow-amber-200 transform hover:-translate-y-1"
            >
              <Download size={24} />
              Terus Download
            </button>
          </div>
        </div>
      </main>

      {showPreview && previewUrl && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-5xl h-[90vh] rounded-2xl flex flex-col overflow-hidden shadow-2xl">
            <div className="p-4 bg-amber-50 border-b border-amber-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-amber-900">Preview Minit Curai</h3>
              <div className="flex gap-2">
                <button
                  onClick={handleDownload}
                  className="flex items-center gap-2 px-4 py-2 bg-amber-600 text-white rounded-lg hover:bg-amber-700 transition-colors"
                >
