              </div>
            </div>
            <div className="flex-grow bg-gray-100 p-4">
              <iframe
                src={previewUrl}
                className="w-full h-full border-none rounded-lg shadow-inner bg-white"
                title="PDF Preview"
              />
            </div>
          </div>
        </div>
      )}

      <footer className="mt-10 text-center text-amber-700/60 text-sm">
        <p>Hak Cipta Terpelihara &copy; {new Date().getFullYear()} - Format PK19/6</p>
      </footer>
    </div>
  );
};

const FormField: React.FC<{ label: string; icon: React.ReactNode; children: React.ReactNode; disabled?: boolean }> = ({ label, icon, children }) => {
  return (
    <div className="flex flex-col gap-2">
      <label className="text-sm font-semibold text-amber-700 flex items-center gap-2">
        {icon}
        {label}
      </label>
      {children}
    </div>
  );
};

export default App;

import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { MinitData } from '../types';

export const generatePDF = (data: MinitData, outputType: 'save' | 'blob' = 'save'): string => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  // Basic settings
  const margin = 15;
  const pageWidth = doc.internal.pageSize.getWidth();
  const contentWidth = pageWidth - (margin * 2);

  // Header text small
  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(8);
  doc.text('PK19 – Pengurusan Sukan Dan Permainan', pageWidth - margin, 10, { align: 'right' });
  doc.line(margin, 12, pageWidth - margin, 12);

  // PK19/6 tag
  doc.setFont('Helvetica', 'bold');
  doc.setFontSize(11);
  doc.text('PK19/6', pageWidth - margin, 18, { align: 'right' });

  // Title
  doc.setFontSize(12);
  doc.text('MINIT CURAI', pageWidth / 2, 25, { align: 'center' });

  // Info Grid (2 columns, 3 rows)
  const gridStartY = 30;
  const rowHeight = 7;
  const colWidth = contentWidth / 2;

  doc.setFontSize(10);
  doc.setFont('Helvetica', 'normal');

  // Drawing the grid for top details
  const drawRow = (y: number, label1: string, value1: string, label2: string, value2: string) => {
    // Left col
    doc.rect(margin, y, colWidth, rowHeight);
    doc.setFont('Helvetica', 'bold');
    doc.text(label1, margin + 2, y + 5);
    doc.setFont('Helvetica', 'normal');
    doc.text(value1 || '', margin + 25, y + 5);

    // Right col
    doc.rect(margin + colWidth, y, colWidth, rowHeight);
    doc.setFont('Helvetica', 'bold');
    doc.text(label2, margin + colWidth + 2, y + 5);
    doc.setFont('Helvetica', 'normal');
    doc.text(value2 || '', margin + colWidth + 25, y + 5);
  };

  const masaDisplay = `${data.masaMula} - ${data.masaTamat}`;

  drawRow(gridStartY, 'PERKARA', data.perkara, 'TARIKH', formatDate(data.tarikh));
  drawRow(gridStartY + rowHeight, 'RUJ. FAIL', data.rujukanFail, 'MASA', masaDisplay);
  drawRow(gridStartY + (rowHeight * 2), 'TEMPAT', data.tempat, 'ANJURAN', data.anjuran);

  // Kehadiran section - AS REQUESTED: EMPTY ANSWER SPACE
  const attendanceY = gridStartY + (rowHeight * 3);
  doc.rect(margin, attendanceY, contentWidth, rowHeight * 2);
  doc.setFont('Helvetica', 'bold');
  doc.text('KEHADIRAN :', margin + 2, attendanceY + 5);
  doc.setFont('Helvetica', 'normal');
  // Leave blank as requested
  doc.text('', margin + 30, attendanceY + 5);

  // Issues Table
  const tableStartY = attendanceY + (rowHeight * 2);

  autoTable(doc, {
    startY: tableStartY,
    margin: { left: margin, right: margin },
    head: [['BIL', 'PERKARA / ISU', 'TINDAKAN / MAKLUMAN']],
    body: data.issues.map((issue, index) => [
      (index + 1).toString(),
      issue.perkara,
      issue.tindakan
    ]),
    theme: 'plain',
    styles: {
      font: 'Helvetica',
      fontSize: 10,
      cellPadding: 3,
      lineColor: [0, 0, 0],
      lineWidth: 0.1,
      textColor: [0, 0, 0],
      valign: 'top',
    },
    headStyles: {
      fillColor: false,
      fontStyle: 'bold',
      halign: 'center',
    },
    columnStyles: {
      0: { cellWidth: 12, halign: 'center' },
      1: { cellWidth: (contentWidth - 12) * 0.7 },
      2: { cellWidth: (contentWidth - 12) * 0.3 },
    },
  });

  // Footer Section (Nama Pencatat & Tarikh)
  const finalY = (doc as any).lastAutoTable.finalY + 5;

  const footerHeight = 15;
  doc.rect(margin, finalY, colWidth, footerHeight);
  doc.setFont('Helvetica', 'normal');
  doc.text('Nama Pencatat :', margin + 2, finalY + 5);
  doc.setFont('Helvetica', 'bold');
  doc.text(data.pencatat || '', margin + 2, finalY + 11);

  doc.rect(margin + colWidth, finalY, colWidth, footerHeight);
  doc.setFont('Helvetica', 'normal');
  doc.text('Tarikh Disediakan :', margin + colWidth + 2, finalY + 5);
  doc.setFont('Helvetica', 'bold');
  doc.text(formatDate(data.tarikhDisediakan) || '', margin + colWidth + 2, finalY + 11);

  // Bottom Copyright Footer
  const pageHeight = doc.internal.pageSize.getHeight();
  doc.setFontSize(7);
  doc.setFont('Helvetica', 'normal');
  doc.line(margin, pageHeight - 20, pageWidth - margin, pageHeight - 20);
  doc.text('Hak Cipta Terpelihara © Sektor Jaminan Kualiti, Jabatan Pendidikan Negeri Johor', margin, pageHeight - 15);
  doc.text('01 Januari 2018 - Keluaran 01 | Pindaan 00', margin, pageHeight - 11);

  const filename = `Minit_Curai_${data.perkara.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`;

  if (outputType === 'save') {
    doc.save(filename);
    return filename;
  } else {
    const blob = doc.output('bloburl');
    return blob as unknown as string;
  }
};

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  return d.toLocaleDateString('ms-MY', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric'
  });
};

payload.text:
Saya telah mengemas kini aplikasi anda mengikut permintaan. Berikut adalah ringkasan perubahan:

1.  **Logo & Tajuk**: Logo sekolah telah diletakkan di bahagian atas dan penerangan di bawah tajuk telah dibuang.
2.  **Butang Baharu**: Butang "Preview PDF" ditukarkan kepada **"Simpan Rekod"** dan butang "Download PDF" ditukarkan kepada **"Jana PDF"**.
3.  **Integrasi Google Drive**: Kedua-dua butang kini akan cuba menghantar fail PDF terus ke folder Google Drive anda.
4.  **Google Apps Script**: Kod backend untuk membolehkan penghantaran ke Drive disediakan di bawah.

### Arahan Penting untuk Google Drive:
Untuk membolehkan fungsi simpan ke Drive berfungsi, anda perlu:
1.  Buka [Google Apps Script](https://script.google.com/).
2.  Cipta projek baharu dan **copy-paste** kod di bawah.
3.  Klik **Deploy** > **New Deployment** > Pilih **Web App**.
4.  Set "Who has access" kepada **"Anyone"**.
5.  Salin URL Web App yang diberikan dan tampal ke dalam fail `index.html` pada bahagian `const GAS_URL`.

**Kod Google Apps Script (GAS):**
```javascript
function doPost(e) {
  try {
    var params = JSON.parse(e.postData.contents);
    var folderId = "1ierZqU1RFQkpQXhLJvGYNIEy6ZeUUzkT"; // ID Folder anda
    var folder = DriveApp.getFolderById(folderId);

    // Decode base64 PDF
    var decoded = Utilities.base64Decode(params.pdfData);
    var blob = Utilities.newBlob(decoded, "application/pdf", params.fileName);

    // Simpan fail
    var file = folder.createFile(blob);

    return ContentService.createTextOutput(JSON.stringify({
      status: "success",
      fileUrl: file.getUrl()
    })).setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({
      status: "error",
      message: err.toString()
    })).setMimeType(ContentService.MimeType.JSON);
  }
}
```

